#include<bits/stdc++.h>
using namespace std;

string a, b;
long long num1 = 1, num2 = 1;

int main() {
	cin >> a >> b;
	for (int i = 0; i < a.size(); i++) {
		num1 = num1 * (a[i] - 'A' + 1);
	}
	for (int i = 0; i < b.size(); i++) {
		num2 = num2 * (b[i] - 'A' + 1);
	}if(num1%47==num2%47){
		cout<<"GO";
	}else{
		cout<<"STAY";
	}
	return 0;
}
